{
  "name": "SchemeGenie - Academic Scheme Book Builder",
  "description": "A production-ready web application for teachers to generate, edit, and export complete academic schemes of work using AI.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Lesson {
  id: string;
  week: number;
  lessonNumber: number;
  topic: string;
  objectives: string;
  concepts: string;
  activities: string;
  resources: string;
  assessment: string;
  homework: string;
  notes: string;
  dateRange: string;
}

export interface SchemeMetadata {
  subject: string;
  grade: string;
  term: string;
  weeks: number;
  lessonsPerWeek: number;
  teacherName: string;
  school: string;
  academicYear: string;
  startDate: string;
}

export interface SchemeBook {
  id: string;
  metadata: SchemeMetadata;
  lessons: Lesson[];
  createdAt: number;
}

export enum SubjectType {
  MATH = 'Math',
  SCIENCE = 'Science',
  ENGLISH = 'English',
  SOCIAL_STUDIES = 'Social Studies',
  ART = 'Art',
  MUSIC = 'Music',
  PHYSICAL_EDUCATION = 'PE'
}

import { GoogleGenAI, Type } from "@google/genai";
import { SchemeMetadata, Lesson } from "../types";

export const generateSchemeContent = async (metadata: SchemeMetadata): Promise<Partial<Lesson>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const totalLessons = metadata.weeks * metadata.lessonsPerWeek;

  const prompt = `
    Act as an expert curriculum developer. Generate a complete academic scheme of work for:
    Subject: ${metadata.subject}
    Grade/Class: ${metadata.grade}
    Term: ${metadata.term}
    Total Weeks: ${metadata.weeks}
    Lessons per Week: ${metadata.lessonsPerWeek}
    Total Lessons: ${totalLessons}

    The progression must be logically sequenced for the grade level. 
    Objectives must be SMART (Specific, Measurable, Achievable, Relevant, Time-bound).
    Activities should be age-appropriate and diverse (group work, discussions, individual tasks).

    Generate exactly ${totalLessons} lessons.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            week: { type: Type.INTEGER },
            lessonNumber: { type: Type.INTEGER },
            topic: { type: Type.STRING },
            objectives: { type: Type.STRING },
            concepts: { type: Type.STRING },
            activities: { type: Type.STRING },
            resources: { type: Type.STRING },
            assessment: { type: Type.STRING },
            homework: { type: Type.STRING },
            notes: { type: Type.STRING },
          },
          required: ["week", "lessonNumber", "topic", "objectives", "concepts", "activities", "resources", "assessment", "homework"],
        }
      }
    }
  });

  try {
    const jsonStr = response.text.trim();
    return JSON.parse(jsonStr);
  } catch (error) {
    console.error("Failed to parse Gemini response", error);
    throw new Error("Failed to generate scheme content. Please try again.");
  }
};

export const getWeekDateRange = (startDateStr: string, weekIndex: number): string => {
  const startDate = new Date(startDateStr);
  if (isNaN(startDate.getTime())) return "TBD";

  const weekStart = new Date(startDate);
  weekStart.setDate(startDate.getDate() + (weekIndex - 1) * 7);

  const weekEnd = new Date(weekStart);
  weekEnd.setDate(weekStart.getDate() + 4); // Mon to Fri

  const options: Intl.DateTimeFormatOptions = { month: 'short', day: 'numeric' };
  return `${weekStart.toLocaleDateString('en-US', options)} - ${weekEnd.toLocaleDateString('en-US', options)}`;
};

export const getAcademicYears = () => {
  const currentYear = new Date().getFullYear();
  return [
    `${currentYear}/${currentYear + 1}`,
    `${currentYear - 1}/${currentYear}`,
    `${currentYear + 1}/${currentYear + 2}`
  ];
};

import { jsPDF } from "jspdf";
import "jspdf-autotable";
import * as XLSX from "xlsx";
import { SchemeBook, Lesson } from "../types";
import { COLUMN_HEADERS } from "../constants";

declare module "jspdf" {
  interface jsPDF {
    autoTable: (options: any) => jsPDF;
  }
}

export const exportToPDF = (scheme: SchemeBook) => {
  const doc = new jsPDF({
    orientation: "landscape",
    unit: "mm",
    format: "a4"
  });

  // Header
  doc.setFontSize(18);
  doc.text("SCHEME OF WORK", 148, 15, { align: "center" });

  doc.setFontSize(10);
  doc.text(`Subject: ${scheme.metadata.subject}`, 14, 25);
  doc.text(`Grade: ${scheme.metadata.grade}`, 14, 30);
  doc.text(`Term: ${scheme.metadata.term}`, 14, 35);
  doc.text(`Teacher: ${scheme.metadata.teacherName}`, 148, 25, { align: "center" });
  doc.text(`School: ${scheme.metadata.school}`, 148, 30, { align: "center" });
  doc.text(`Academic Year: ${scheme.metadata.academicYear}`, 148, 35, { align: "center" });
  doc.text(`Weeks: ${scheme.metadata.weeks}`, 280, 25, { align: "right" });
  doc.text(`Lessons/Week: ${scheme.metadata.lessonsPerWeek}`, 280, 30, { align: "right" });

  const body = scheme.lessons.map(l => [
    l.week,
    l.dateRange,
    l.lessonNumber,
    l.topic,
    l.objectives,
    l.concepts,
    l.activities,
    l.resources,
    l.assessment,
    l.homework,
    l.notes
  ]);

  doc.autoTable({
    startY: 45,
    head: [COLUMN_HEADERS],
    body: body,
    theme: 'grid',
    styles: { fontSize: 7, cellPadding: 1 },
    headStyles: { fillColor: [51, 65, 85] },
    columnStyles: {
      0: { cellWidth: 10 },
      1: { cellWidth: 20 },
      2: { cellWidth: 12 },
    }
  });

  doc.save(`${scheme.metadata.subject}_Grade${scheme.metadata.grade}_Term${scheme.metadata.term}_Scheme.pdf`);
};

export const exportToExcel = (scheme: SchemeBook) => {
  const data = scheme.lessons.map(l => ({
    "Week": l.week,
    "Date Range": l.dateRange,
    "Lesson #": l.lessonNumber,
    "Topic": l.topic,
    "Learning Objectives": l.objectives,
    "Key Concepts": l.concepts,
    "Activities": l.activities,
    "Resources": l.resources,
    "Assessment": l.assessment,
    "HW/Assignment": l.homework,
    "Notes": l.notes
  }));

  const worksheet = XLSX.utils.json_to_sheet(data);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Scheme of Work");

  // Create a blob and trigger download
  XLSX.writeFile(workbook, `${scheme.metadata.subject}_Scheme.xlsx`);
};

