// Fix: Removed module augmentation for "jspdf" which was causing a "module cannot be found" error.
// Switched to the modern functional approach of jspdf-autotable for better type compatibility.

export const exportToPDF = (scheme: SchemeBook) => {
  const doc = new jsPDF({
    orientation: "landscape",
    unit: "mm",
    format: "a4"
  });

  // Header
  doc.setFontSize(18);
  doc.text("SCHEME OF WORK", 148, 15, { align: "center" });

  doc.setFontSize(10);
  doc.text(`Subject: ${scheme.metadata.subject}`, 14, 25);
  doc.text(`Grade: ${scheme.metadata.grade}`, 14, 30);
  doc.text(`Term: ${scheme.metadata.term}`, 14, 35);
  doc.text(`Teacher: ${scheme.metadata.teacherName}`, 148, 25, { align: "center" });
  doc.text(`School: ${scheme.metadata.school}`, 148, 30, { align: "center" });
  doc.text(`Academic Year: ${scheme.metadata.academicYear}`, 148, 35, { align: "center" });
  doc.text(`Weeks: ${scheme.metadata.weeks}`, 280, 25, { align: "right" });
  doc.text(`Lessons/Week: ${scheme.metadata.lessonsPerWeek}`, 280, 30, { align: "right" });

  const body = scheme.lessons.map(l => [
    l.week,
    l.dateRange,
    l.lessonNumber,
    l.topic,
    l.objectives,
    l.concepts,
    l.activities,
    l.resources,
    l.assessment,
    l.homework,
    l.notes
  ]);

  // Fix: Use the autoTable function directly instead of doc.autoTable to avoid augmentation errors
  autoTable(doc, {
    startY: 45,
    head: [COLUMN_HEADERS],
    body: body,
    theme: 'grid',
    styles: { fontSize: 7, cellPadding: 1 },
    headStyles: { fillColor: [51, 65, 85] },
    columnStyles: {
      0: { cellWidth: 10 },
      1: { cellWidth: 20 },
      2: { cellWidth: 12 },
    }
  });

  doc.save(`${scheme.metadata.subject}_Grade${scheme.metadata.grade}_Term${scheme.metadata.term}_Scheme.pdf`);
};

export const exportToExcel = (scheme: SchemeBook) => {
