const RichNoteCell: React.FC<{
  value: string;
  onChange: (val: string) => void;
}> = ({ value, onChange }) => {
  const editorRef = useRef<HTMLDivElement>(null);
  const [isFocused, setIsFocused] = useState(false);

  const handleCommand = (command: string) => {
    document.execCommand(command, false);
    if (editorRef.current) {
      onChange(editorRef.current.innerHTML);
    }
  };

  return (
    <div className="relative group flex flex-col min-h-[120px]">
      {isFocused && (
        <div className="absolute -top-10 left-0 flex items-center gap-1 bg-white border border-slate-200 shadow-sm rounded-md p-1 z-10 no-print">
          <button
            onMouseDown={(e) => { e.preventDefault(); handleCommand('bold'); }}
            className="p-1 hover:bg-slate-100 rounded text-slate-600"
            title="Bold"
          >
            <Bold className="w-3.5 h-3.5" />
          </button>
          <button
            onMouseDown={(e) => { e.preventDefault(); handleCommand('italic'); }}
            className="p-1 hover:bg-slate-100 rounded text-slate-600"
            title="Italic"
          >
            <Italic className="w-3.5 h-3.5" />
          </button>
          <button
            onMouseDown={(e) => { e.preventDefault(); handleCommand('insertUnorderedList'); }}
            className="p-1 hover:bg-slate-100 rounded text-slate-600"
            title="Bullet List"
          >
            <List className="w-3.5 h-3.5" />
          </button>
        </div>
      )}
      <div
        ref={editorRef}
        contentEditable
        onFocus={() => setIsFocused(true)}
        onBlur={() => {
          setIsFocused(false);
          if (editorRef.current) {
            onChange(editorRef.current.innerHTML);
          }
        }}
        className="w-full h-full min-h-[120px] bg-transparent border-none focus:ring-1 focus:ring-indigo-500 rounded p-2 text-xs outline-none overflow-y-auto rich-text-area"
        dangerouslySetInnerHTML={{ __html: value }}
      />
      <style>{`
