import React, { useState, useEffect, useCallback } from 'react';
import { Download, FileSpreadsheet, FileText, Layout, RotateCcw, Share2, Printer, PlusCircle, Save } from 'lucide-react';
import InputForm from './components/InputForm';
import SchemeTable from './components/SchemeTable';
import LoadingOverlay from './components/LoadingOverlay';
import { SchemeBook, SchemeMetadata, Lesson } from './types';
import { generateSchemeContent } from './services/geminiService';
import { getWeekDateRange } from './utils/dateUtils';
import { exportToPDF, exportToExcel } from './utils/exportUtils';

const STORAGE_KEY = 'schemegenie_drafts';

const App: React.FC = () => {
  const [activeScheme, setActiveScheme] = useState<SchemeBook | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Load from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed) && parsed.length > 0) {
          setActiveScheme(parsed[0]);
        }
      } catch (e) {
        console.error("Failed to load saved drafts", e);
      }
    }
  }, []);

  // Save to local storage whenever activeScheme changes
  useEffect(() => {
    if (activeScheme) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify([activeScheme]));
    }
  }, [activeScheme]);

  const handleGenerate = async (metadata: SchemeMetadata) => {
    setIsLoading(true);
    setError(null);
    try {
      const lessonData = await generateSchemeContent(metadata);

      const completeLessons: Lesson[] = lessonData.map((l, index) => {
        const week = l.week || Math.floor(index / metadata.lessonsPerWeek) + 1;
        return {
          id: `lesson-${Date.now()}-${index}`,
          week: week,
          lessonNumber: l.lessonNumber || (index % metadata.lessonsPerWeek) + 1,
          topic: l.topic || '',
          objectives: l.objectives || '',
          concepts: l.concepts || '',
          activities: l.activities || '',
          resources: l.resources || '',
          assessment: l.assessment || '',
          homework: l.homework || '',
          notes: l.notes || '',
          dateRange: getWeekDateRange(metadata.startDate, week)
        };
      });

      const newScheme: SchemeBook = {
        id: `scheme-${Date.now()}`,
        metadata,
        lessons: completeLessons,
        createdAt: Date.now()
      };

      setActiveScheme(newScheme);
    } catch (err: any) {
      setError(err.message || "Something went wrong during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const updateLesson = (id: string, field: keyof Lesson, value: string) => {
    if (!activeScheme) return;
    setActiveScheme({
      ...activeScheme,
      lessons: activeScheme.lessons.map(l => l.id === id ? { ...l, [field]: value } : l)
    });
  };

  const handleReset = () => {
    if (confirm("Are you sure? This will delete your current draft.")) {
      setActiveScheme(null);
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  return (
    <div className="min-h-screen pb-20">
      {/* Header */}
      <header className="bg-slate-800 text-white shadow-lg no-print">
        <div className="container mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <Layout className="w-6 h-6 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">SchemeGenie</h1>
              <p className="text-xs text-indigo-300 font-medium">Curriculum AI Assistant</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
            {activeScheme && (
              <div className="hidden md:flex items-center gap-2">
                 <button 
                  onClick={() => exportToPDF(activeScheme)}
                  className="flex items-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors"
                >
                  <Download className="w-4 h-4" /> PDF
                </button>
                <button 
                  onClick={() => exportToExcel(activeScheme)}
                  className="flex items-center gap-2 bg-emerald-700 hover:bg-emerald-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors"
                >
                  <FileSpreadsheet className="w-4 h-4" /> Excel
                </button>
              </div>
            )}
            <button 
              onClick={handleReset}
              className="p-2 hover:bg-slate-700 rounded-lg text-slate-400 hover:text-white transition-colors"
              title="Reset All"
            >
              <RotateCcw className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="container mx-auto px-6 py-8">
        {!activeScheme ? (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="text-center space-y-4 py-10">
              <h2 className="text-4xl font-extrabold text-slate-800">Complete Academic Schemes in Seconds</h2>
              <p className="text-lg text-slate-500 max-w-2xl mx-auto">
                Stop spending weekends lesson planning. Input your subject details and let our AI generate a production-ready scheme of work tailored to your level.
              </p>
            </div>

            <InputForm onGenerate={handleGenerate} />

            {error && (
              <div className="bg-red-50 border border-red-200 text-red-700 px-6 py-4 rounded-xl flex items-center gap-3 shadow-sm">
                <div className="bg-red-100 p-2 rounded-full">
                  <Layout className="w-5 h-5 text-red-600" />
                </div>
                {error}
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-8 animate-in fade-in duration-500">
            {/* Metadata Preview */}
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-wrap items-center justify-between gap-6 no-print">
              <div className="flex gap-8">
                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider block mb-1">Subject & Form</label>
                  <p className="text-lg font-bold text-slate-800">{activeScheme.metadata.subject} — {activeScheme.metadata.form}</p>
                </div>
                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider block mb-1">Term & Year</label>
                  <p className="text-lg font-bold text-slate-800">Term {activeScheme.metadata.term} ({activeScheme.metadata.academicYear})</p>
                </div>
                <div>
                  <label className="text-xs font-bold text-slate-400 uppercase tracking-wider block mb-1">Teacher</label>
                  <p className="text-lg font-bold text-slate-800">{activeScheme.metadata.teacherName || 'Not specified'}</p>
                </div>
              </div>
              <div className="flex gap-3">
                <button 
                  onClick={() => setActiveScheme(null)}
                  className="bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 px-4 py-2 rounded-lg text-sm font-semibold transition-all flex items-center gap-2"
                >
                  <PlusCircle className="w-4 h-4" /> Create New
                </button>
                <button 
                   onClick={() => window.print()}
                   className="bg-indigo-50 text-indigo-700 hover:bg-indigo-100 px-4 py-2 rounded-lg text-sm font-semibold transition-all flex items-center gap-2"
                >
                  <Printer className="w-4 h-4" /> Print
                </button>
              </div>
            </div>

            {/* Editing Tools Bar */}
            <div className="flex items-center justify-between bg-slate-50 p-2 rounded-lg border border-slate-200 no-print">
               <div className="text-sm text-slate-500 font-medium px-2">
                 <span className="text-indigo-600 font-bold">{activeScheme.lessons.length}</span> Lessons Generated. Cells are editable.
               </div>
               <div className="flex gap-2">
                  <button onClick={() => exportToPDF(activeScheme)} className="flex md:hidden items-center gap-2 bg-slate-800 text-white px-3 py-1.5 rounded-md text-xs font-medium">
                    <Download className="w-3 h-3" /> PDF
                  </button>
               </div>
            </div>

            {/* Scheme Table */}
            <SchemeTable 
              lessons={activeScheme.lessons} 
              onUpdateLesson={updateLesson} 
            />

            {/* Footer Summary Blocks */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mt-12">
              <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 border-b pb-2">Assessment Summary</h3>
                <p className="text-slate-600 text-sm leading-relaxed">
                  The term includes a mix of formative and summative assessments. 
                  Weekly quizzes are recommended for concepts introduced early in the weeks, 
                  with a mid-term project in Week 6 and a comprehensive end-of-term examination 
                  during the final two weeks of the schedule.
                </p>
              </div>
              <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 border-b pb-2">Required Resources</h3>
                <p className="text-slate-600 text-sm leading-relaxed">
                  Standard level textbooks, interactive whiteboards, curated online videos, 
                  and individual student workstations. Some activities require specialized materials 
                  (manipulatives for Math, laboratory apparatus for Science) as specified in the lessons above.
                </p>
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Loading Screen */}
      {isLoading && <LoadingOverlay />}

      {/* Floating Action Button (Mobile Only) */}
      {!isLoading && activeScheme && (
        <div className="fixed bottom-6 right-6 flex flex-col gap-3 md:hidden no-print">
          <button 
            onClick={() => exportToPDF(activeScheme)}
            className="w-12 h-12 bg-indigo-600 text-white rounded-full shadow-lg flex items-center justify-center"
          >
            <Download className="w-6 h-6" />
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

import { jsPDF } from "jspdf";
import autoTable from "jspdf-autotable";
import * as XLSX from "xlsx";
import { SchemeBook, Lesson } from "../types";
import { COLUMN_HEADERS } from "../constants";

const stripHtml = (html: string) => {
  const tmp = document.createElement("DIV");
  tmp.innerHTML = html;
  return tmp.textContent || tmp.innerText || "";
};

export const exportToPDF = (scheme: SchemeBook) => {
  const doc = new jsPDF({
    orientation: "landscape",
    unit: "mm",
    format: "a4"
  });

  // Header
  doc.setFontSize(18);
  doc.text("SCHEME OF WORK", 148, 15, { align: "center" });

  doc.setFontSize(10);
  doc.text(`Subject: ${scheme.metadata.subject}`, 14, 25);
  doc.text(`Form: ${scheme.metadata.form}`, 14, 30);
  doc.text(`Term: ${scheme.metadata.term}`, 14, 35);
  doc.text(`Teacher: ${scheme.metadata.teacherName}`, 148, 25, { align: "center" });
  doc.text(`School: ${scheme.metadata.school}`, 148, 30, { align: "center" });
  doc.text(`Academic Year: ${scheme.metadata.academicYear}`, 148, 35, { align: "center" });
  doc.text(`Weeks: ${scheme.metadata.weeks}`, 280, 25, { align: "right" });
  doc.text(`Lessons/Week: ${scheme.metadata.lessonsPerWeek}`, 280, 30, { align: "right" });

  const body = scheme.lessons.map(l => [
    l.week,
    l.dateRange,
    l.lessonNumber,
    l.topic,
    l.objectives,
    l.concepts,
    l.activities,
    l.resources,
    l.assessment,
    l.homework,
    stripHtml(l.notes)
  ]);

  autoTable(doc, {
    startY: 45,
    head: [COLUMN_HEADERS],
    body: body,
    theme: 'grid',
    styles: { fontSize: 7, cellPadding: 1 },
    headStyles: { fillColor: [51, 65, 85] },
    columnStyles: {
      0: { cellWidth: 10 },
      1: { cellWidth: 20 },
      2: { cellWidth: 12 },
    }
  });

  doc.save(`${scheme.metadata.subject}_Form${scheme.metadata.form}_Term${scheme.metadata.term}_Scheme.pdf`);
};

export const exportToExcel = (scheme: SchemeBook) => {
  const data = scheme.lessons.map(l => ({
    "Week": l.week,
    "Date Range": l.dateRange,
    "Lesson #": l.lessonNumber,
    "Topic": l.topic,
    "Learning Objectives": l.objectives,
    "Key Concepts": l.concepts,
    "Activities": l.activities,
    "Resources": l.resources,
    "Assessment": l.assessment,
    "HW/Assignment": l.homework,
    "Notes": stripHtml(l.notes)
  }));

  const worksheet = XLSX.utils.json_to_sheet(data);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Scheme of Work");

  XLSX.writeFile(workbook, `${scheme.metadata.subject}_Form_${scheme.metadata.form}_Scheme.xlsx`);
};

