import { GoogleGenAI, Type } from "@google/genai";
import { SchemeMetadata, Lesson } from "../types";

export const generateSchemeContent = async (metadata: SchemeMetadata): Promise<Partial<Lesson>[]> => {
  // Fix: Use process.env.API_KEY directly as per SDK guidelines to ensure proper authentication
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const totalLessons = metadata.weeks * metadata.lessonsPerWeek;

  const prompt = `
    Act as an expert curriculum developer. Generate a complete academic scheme of work for:
    Subject: ${metadata.subject}
    Form/Class: ${metadata.form}
    Term: ${metadata.term}
    Total Weeks: ${metadata.weeks}
    Lessons per Week: ${metadata.lessonsPerWeek}
    Total Lessons: ${totalLessons}

    The progression must be logically sequenced for the academic level. 
    Objectives must be SMART (Specific, Measurable, Achievable, Relevant, Time-bound).
    Activities should be age-appropriate and diverse (group work, discussions, individual tasks).
    Include an 'evaluation' section for each lesson which suggests how the teacher might evaluate the lesson's success.

    Generate exactly ${totalLessons} lessons.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            week: { type: Type.INTEGER },
            lessonNumber: { type: Type.INTEGER },
            topic: { type: Type.STRING },
            objectives: { type: Type.STRING },
            concepts: { type: Type.STRING },
            activities: { type: Type.STRING },
            resources: { type: Type.STRING },
            assessment: { type: Type.STRING },
            homework: { type: Type.STRING },
            evaluation: { type: Type.STRING },
          },
          required: ["week", "lessonNumber", "topic", "objectives", "concepts", "activities", "resources", "assessment", "homework", "evaluation"],
        }
      }
    }
  });

  try {
    const jsonStr = response.text.trim();
    return JSON.parse(jsonStr);
  } catch (error) {
    console.error("Failed to parse Gemini response", error);
    throw new Error("Failed to generate scheme content. Please try again.");
  }
};

