const stripHtml = (html: string) => {
  const tmp = document.createElement("DIV");
  tmp.innerHTML = html;
  return tmp.textContent || tmp.innerText || "";
};

export const exportLessonHandout = (lesson: Lesson, metadata: SchemeMetadata) => {
  const doc = new jsPDF({
    orientation: "portrait",
    unit: "mm",
    format: "a4"
  });

  // Header Box
  doc.setFillColor(240, 244, 248);
  doc.rect(0, 0, 210, 40, 'F');

  doc.setFontSize(18);
  doc.setTextColor(30, 41, 59);
  doc.setFont("helvetica", "bold");
  doc.text(lesson.topic, 105, 15, { align: "center" });

  doc.setFontSize(10);
  doc.setFont("helvetica", "normal");
  doc.text(`${metadata.subject} | Form ${metadata.form} | Term ${metadata.term}`, 105, 22, { align: "center" });
  doc.text(`Lesson ${lesson.lessonNumber} | Week ${lesson.week}`, 105, 28, { align: "center" });

  // Body Content
  doc.setFontSize(12);
  doc.setTextColor(51, 65, 85);
  doc.text("Lesson Handout", 14, 50);
  doc.setLineWidth(0.5);
  doc.line(14, 52, 50, 52);

  const splitText = doc.splitTextToSize(lesson.resourceHandout || "No handout content generated.", 182);
  doc.setFontSize(10);
  doc.text(splitText, 14, 60);

  // Footer
  doc.setFontSize(8);
  doc.setTextColor(148, 163, 184);
  doc.text(`Generated by SchemeGenie AI for ${metadata.school || 'Academic Use'}`, 105, 285, { align: "center" });

  doc.save(`${metadata.subject}_L${lesson.lessonNumber}_Handout.pdf`);
};

export const exportToPDF = (scheme: SchemeBook) => {
  const doc = new jsPDF({
    orientation: "landscape",
    unit: "mm",
    format: "a4"
  });

  doc.setFontSize(18);
  doc.text("SCHEME OF WORK", 148, 15, { align: "center" });

  doc.setFontSize(10);
  doc.text(`Subject: ${scheme.metadata.subject}`, 14, 25);
  doc.text(`Form: ${scheme.metadata.form}`, 14, 30);
  doc.text(`Term: ${scheme.metadata.term}`, 14, 35);
  doc.text(`Teacher: ${scheme.metadata.teacherName}`, 148, 25, { align: "center" });
  doc.text(`School: ${scheme.metadata.school}`, 148, 30, { align: "center" });
  doc.text(`Academic Year: ${scheme.metadata.academicYear}`, 148, 35, { align: "center" });
  doc.text(`Weeks: ${scheme.metadata.weeks}`, 280, 25, { align: "right" });
  doc.text(`Lessons/Week: ${scheme.metadata.lessonsPerWeek}`, 280, 30, { align: "right" });

  const body = scheme.lessons.map(l => [
    l.week,
    l.dateRange,
    l.lessonNumber,
    l.topic,
    l.objectives,
    l.concepts,
    l.activities,
    l.resources,
    l.assessment,
    l.homework,
    stripHtml(l.evaluation)
  ]);

  // We exclude the Actions column from the PDF table as buttons aren't printable/relevant there
  const pdfHeaders = COLUMN_HEADERS.slice(0, -1);

  autoTable(doc, {
    startY: 45,
    head: [pdfHeaders],
    body: body,
    theme: 'grid',
    styles: { fontSize: 7, cellPadding: 1 },
    headStyles: { fillColor: [51, 65, 85] },
    columnStyles: {
      0: { cellWidth: 8 },
      1: { cellWidth: 18 },
      2: { cellWidth: 8 },
    }
  });

  doc.save(`${scheme.metadata.subject}_Form${scheme.metadata.form}_Scheme.pdf`);
};

export const exportToExcel = (scheme: SchemeBook) => {
  const data = scheme.lessons.map(l => ({
    "Week": l.week,
    "Date Range": l.dateRange,
    "Lesson #": l.lessonNumber,
    "Topic": l.topic,
    "Learning Objectives": l.objectives,
    "Key Concepts": l.concepts,
    "Activities": l.activities,
    "Resources": l.resources,
    "Assessment": l.assessment,
    "HW/Assignment": l.homework,
    "Evaluation": stripHtml(l.evaluation)
  }));

  const worksheet = XLSX.utils.json_to_sheet(data);
  const workbook = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(workbook, worksheet, "Scheme of Work");

  XLSX.writeFile(workbook, `${scheme.metadata.subject}_Scheme.xlsx`);
};

