import React, { useState, useEffect, useCallback } from 'react';
import { Download, FileSpreadsheet, Layout, RotateCcw, Printer, PlusCircle, Sparkles } from 'lucide-react';
import InputForm from './components/InputForm';
import SchemeTable from './components/SchemeTable';
import LoadingOverlay from './components/LoadingOverlay';
import { SchemeBook, SchemeMetadata, Lesson } from './types';
import { generateSchemeContent } from './services/geminiService';
import { getWeekDateRange } from './utils/dateUtils';
import { exportToPDF, exportToExcel } from './utils/exportUtils';

const STORAGE_KEY = 'schemegenie_drafts';

const App: React.FC = () => {
  const [activeScheme, setActiveScheme] = useState<SchemeBook | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed) && parsed.length > 0) {
          setActiveScheme(parsed[0]);
        }
      } catch (e) {
        console.error("Failed to load saved drafts", e);
      }
    }
  }, []);

  useEffect(() => {
    if (activeScheme) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify([activeScheme]));
    }
  }, [activeScheme]);

  const handleGenerate = async (metadata: SchemeMetadata, syllabusFile?: { data: string, mimeType: string }) => {
    setIsLoading(true);
    setError(null);
    try {
      const lessonData = await generateSchemeContent(metadata, syllabusFile);

      const completeLessons: Lesson[] = lessonData.map((l, index) => {
        const week = l.week || Math.floor(index / metadata.lessonsPerWeek) + 1;
        return {
          id: `lesson-${Date.now()}-${index}`,
          week: week,
          lessonNumber: l.lessonNumber || (index % metadata.lessonsPerWeek) + 1,
          topic: l.topic || '',
          objectives: l.objectives || '',
          concepts: l.concepts || '',
          activities: l.activities || '',
          resources: l.resources || '',
          assessment: l.assessment || '',
          homework: l.homework || '',
          evaluation: l.evaluation || '',
          resourceHandout: l.resourceHandout || '',
          dateRange: getWeekDateRange(metadata.startDate, week)
        };
      });

      const newScheme: SchemeBook = {
        id: `scheme-${Date.now()}`,
        metadata,
        lessons: completeLessons,
        createdAt: Date.now()
      };

      setActiveScheme(newScheme);
    } catch (err: any) {
      setError(err.message || "Failed to generate scheme book.");
    } finally {
      setIsLoading(false);
    }
  };

  const updateLesson = (id: string, field: keyof Lesson, value: string) => {
    if (!activeScheme) return;
    setActiveScheme({
      ...activeScheme,
      lessons: activeScheme.lessons.map(l => l.id === id ? { ...l, [field]: value } : l)
    });
  };

  const handleReset = () => {
    if (confirm("Reset current draft?")) {
      setActiveScheme(null);
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  return (
    <div className="min-h-screen pb-20">
      <header className="bg-slate-800 text-white shadow-lg no-print">
        <div className="container mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <Layout className="w-6 h-6 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">SchemeGenie</h1>
              <p className="text-xs text-indigo-300 font-medium italic">Powered by AI Education</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
            {activeScheme && (
              <div className="hidden md:flex items-center gap-2">
                 <button onClick={() => exportToPDF(activeScheme)} className="flex items-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors">
                  <Download className="w-4 h-4" /> PDF
                </button>
                <button onClick={() => exportToExcel(activeScheme)} className="flex items-center gap-2 bg-emerald-700 hover:bg-emerald-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors">
                  <FileSpreadsheet className="w-4 h-4" /> Excel
                </button>
              </div>
            )}
            <button onClick={handleReset} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400 hover:text-white transition-colors">
              <RotateCcw className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-6 py-8">
        {!activeScheme ? (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="text-center space-y-4 py-10">
              <h2 className="text-4xl font-extrabold text-slate-800 tracking-tight">AI Academic Planning</h2>
              <p className="text-lg text-slate-500 max-w-2xl mx-auto leading-relaxed">
                Transform your <span className="text-indigo-600 font-semibold underline">syllabus</span> into a full termly scheme book with individual student handouts for every lesson.
              </p>
            </div>

            <InputForm onGenerate={handleGenerate} />

            {error && (
              <div className="bg-red-50 border border-red-200 text-red-700 px-6 py-4 rounded-xl flex items-center gap-3">
                <Layout className="w-5 h-5 text-red-600" />
                {error}
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-wrap items-center justify-between gap-6 no-print">
              <div className="flex gap-8">
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1">Subject & Form</label>
                  <p className="text-lg font-bold text-slate-800">{activeScheme.metadata.subject} — Form {activeScheme.metadata.form}</p>
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1">Term</label>
                  <p className="text-lg font-bold text-slate-800">Term {activeScheme.metadata.term}</p>
                </div>
              </div>
              <div className="flex gap-3">
                <button onClick={() => setActiveScheme(null)} className="bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 px-4 py-2 rounded-lg text-sm font-semibold transition-all flex items-center gap-2">
                  <PlusCircle className="w-4 h-4" /> New Scheme
                </button>
                <button onClick={() => window.print()} className="bg-indigo-50 text-indigo-700 hover:bg-indigo-100 px-4 py-2 rounded-lg text-sm font-semibold transition-all flex items-center gap-2">
                  <Printer className="w-4 h-4" /> Print
                </button>
              </div>
            </div>

            <div className="flex items-center gap-2 bg-indigo-50 text-indigo-700 p-3 rounded-lg border border-indigo-100 no-print">
              <Sparkles className="w-4 h-4" />
              <span className="text-xs font-semibold uppercase tracking-wider">AI Feature:</span>
              <span className="text-xs font-medium">Click "Handout" in any row to download student resources.</span>
            </div>

            <SchemeTable 
              lessons={activeScheme.lessons} 
              metadata={activeScheme.metadata}
              onUpdateLesson={updateLesson} 
            />

            <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mt-12">
              <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 border-b pb-2">Assessment Summary</h3>
                <p className="text-slate-600 text-sm leading-relaxed">
                  Term plan incorporates standardized assessments and AI-suggested quizzes.
                </p>
              </div>
              <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
                <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 border-b pb-2">Resource Inventory</h3>
                <p className="text-slate-600 text-sm leading-relaxed">
                  All handouts for individual lessons are pre-generated and available for download.
                </p>
              </div>
            </div>
          </div>
        )}
      </main>

      {isLoading && <LoadingOverlay />}
    </div>
  );
};

export default App;

