import { GoogleGenAI, Type } from "@google/genai";
import { SchemeMetadata, Lesson } from "../types";

export const generateSchemeContent = async (
  metadata: SchemeMetadata, 
  syllabusFile?: { data: string, mimeType: string }
): Promise<Partial<Lesson>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const totalLessons = metadata.weeks * metadata.lessonsPerWeek;

  const textPrompt = `
    Act as an expert curriculum developer. Generate a complete academic scheme of work for:
    Subject: ${metadata.subject}
    Form/Class: ${metadata.form}
    Term: ${metadata.term}
    Total Weeks: ${metadata.weeks}
    Lessons per Week: ${metadata.lessonsPerWeek}
    Total Lessons: ${totalLessons}

    ${syllabusFile ? 'EXTRACT TOPICS AND CONTENT DIRECTLY FROM THE ATTACHED SYLLABUS PDF.' : 'Use standard curriculum guidelines.'}

    REQUIREMENTS FOR EACH LESSON:
    1. Logically sequenced progression.
    2. SMART objectives.
    3. 'lessonPlanContent': Detailed teacher notes (Warm-up, Main, Wrap-up, Materials).
    4. 'worksheetContent': Student worksheet with 3-5 specific practice problems.
    5. 'slidesContent': Array of 5 strings, each describing the content for a single presentation slide.
    6. 'videoGuideDescription': A 2-sentence guide on what a short explainer video for this topic should cover.

    Format the output as a JSON array of exactly ${totalLessons} lesson objects.
  `;

  const contents = syllabusFile 
    ? { parts: [{ text: textPrompt }, { inlineData: syllabusFile }] }
    : textPrompt;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: contents,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            week: { type: Type.INTEGER },
            lessonNumber: { type: Type.INTEGER },
            topic: { type: Type.STRING },
            objectives: { type: Type.STRING },
            concepts: { type: Type.STRING },
            activities: { type: Type.STRING },
            resources: { type: Type.STRING },
            assessment: { type: Type.STRING },
            homework: { type: Type.STRING },
            evaluation: { type: Type.STRING },
            lessonPlanContent: { type: Type.STRING },
            worksheetContent: { type: Type.STRING },
            slidesContent: { type: Type.ARRAY, items: { type: Type.STRING } },
            videoGuideDescription: { type: Type.STRING },
          },
          required: [
            "week", "lessonNumber", "topic", "objectives", "concepts", 
            "activities", "resources", "assessment", "homework", 
            "evaluation", "lessonPlanContent", "worksheetContent", 
            "slidesContent", "videoGuideDescription"
          ],
        }
      }
    }
  });

  try {
    const jsonStr = response.text.trim();
    return JSON.parse(jsonStr);
  } catch (error) {
    console.error("Failed to parse Gemini response", error);
    throw new Error("Failed to generate scheme content. If you uploaded a syllabus, please ensure it's a valid PDF.");
  }
};

