import React, { useState, useEffect } from 'react';
import { Download, FileSpreadsheet, Layout, RotateCcw, Printer, PlusCircle, Sparkles, FolderArchive, Package, Info } from 'lucide-react';
import InputForm from './components/InputForm';
import SchemeTable from './components/SchemeTable';
import LoadingOverlay from './components/LoadingOverlay';
import { SchemeBook, SchemeMetadata, Lesson } from './types';
import { generateSchemeBook, generateLessonResourcesContent } from './services/geminiService';
import { getWeekEndingDate } from './utils/dateUtils';
import { exportToPDF, exportToExcel, downloadFullPackageZip } from './utils/exportUtils';

const STORAGE_KEY = 'schemegenie_v3';

const App: React.FC = () => {
  const [activeScheme, setActiveScheme] = useState<SchemeBook | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isExportingFull, setIsExportingFull] = useState(false);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        if (Array.isArray(parsed) && parsed.length > 0) {
          setActiveScheme(parsed[0]);
        }
      } catch (e) {
        console.error("Failed to load saved drafts", e);
      }
    }
  }, []);

  useEffect(() => {
    if (activeScheme) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify([activeScheme]));
    }
  }, [activeScheme]);

  const handleGenerate = async (metadata: SchemeMetadata, syllabusFile?: { data: string, mimeType: string }) => {
    setIsLoading(true);
    setError(null);
    try {
      const lessonData = await generateSchemeBook(metadata, syllabusFile);

      const completeLessons: Lesson[] = lessonData.map((l, index) => {
        const week = l.week || Math.floor(index / metadata.lessonsPerWeek) + 1;
        return {
          id: `lesson-${Date.now()}-${index}`,
          week: week,
          lessonNumber: l.lessonNumber || (index % metadata.lessonsPerWeek) + 1,
          topic: l.topic || '',
          objectives: l.objectives || '',
          concepts: l.concepts || '',
          activities: l.activities || '',
          resources: l.resources || '',
          assessment: l.assessment || '',
          homework: l.homework || '',
          evaluation: l.evaluation || '',
          weekEnding: getWeekEndingDate(metadata.startDate, week),
        };
      });

      const newScheme: SchemeBook = {
        id: `scheme-${Date.now()}`,
        metadata,
        lessons: completeLessons,
        createdAt: Date.now()
      };

      setActiveScheme(newScheme);
    } catch (err: any) {
      setError("AI is currently busy or the syllabus is too large. Please try again with fewer weeks or a simpler subject.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleGenerateResources = async (lesson: Lesson) => {
    if (!activeScheme) return;

    // Set loading state for this lesson
    updateLesson(lesson.id, 'isGeneratingResources', true);

    try {
      const resources = await generateLessonResourcesContent(lesson, activeScheme.metadata);

      setActiveScheme(prev => {
        if (!prev) return null;
        return {
          ...prev,
          lessons: prev.lessons.map(l => l.id === lesson.id ? { 
            ...l, 
            ...resources, 
            isGeneratingResources: false 
          } : l)
        };
      });
    } catch (err) {
      alert("Failed to build bundle for this lesson. Please try again.");
      updateLesson(lesson.id, 'isGeneratingResources', false);
    }
  };

  const handleFullPackageDownload = async () => {
    if (!activeScheme) return;

    const missingResources = activeScheme.lessons.filter(l => !l.lessonPlanContent);
    if (missingResources.length > 0) {
      if (!confirm(`You have ${missingResources.length} lessons without generated bundles. They will only contain basic placeholders in the full package. Proceed?`)) {
        return;
      }
    }

    setIsExportingFull(true);
    try {
      await downloadFullPackageZip(activeScheme);
    } catch (e) {
      alert("Error packaging resources. Try again.");
    } finally {
      setIsExportingFull(false);
    }
  };

  const updateLesson = (id: string, field: keyof Lesson, value: any) => {
    setActiveScheme(prev => {
      if (!prev) return null;
      return {
        ...prev,
        lessons: prev.lessons.map(l => l.id === id ? { ...l, [field]: value } : l)
      };
    });
  };

  const handleReset = () => {
    if (confirm("Reset everything? Draft will be lost.")) {
      setActiveScheme(null);
      localStorage.removeItem(STORAGE_KEY);
    }
  };

  return (
    <div className="min-h-screen pb-20">
      <header className="bg-slate-800 text-white shadow-lg no-print">
        <div className="container mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-lg">
              <Package className="w-6 h-6 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight">SchemeGenie</h1>
              <p className="text-xs text-indigo-300 font-medium italic">Advanced Curriculum Hub</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
            {activeScheme && (
              <div className="hidden md:flex items-center gap-2">
                <button 
                  onClick={handleFullPackageDownload} 
                  disabled={isExportingFull}
                  className="flex items-center gap-2 bg-indigo-600 hover:bg-indigo-500 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-md disabled:opacity-50 transition-all"
                >
                  <FolderArchive className="w-4 h-4" />
                  Package Export
                </button>
                <div className="h-6 w-px bg-slate-700 mx-1"></div>
                <button onClick={() => exportToPDF(activeScheme)} className="flex items-center gap-2 bg-slate-700 hover:bg-slate-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition-colors">
                  <Download className="w-4 h-4" /> PDF
                </button>
              </div>
            )}
            <button onClick={handleReset} className="p-2 hover:bg-slate-700 rounded-lg text-slate-400 hover:text-white transition-colors">
              <RotateCcw className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      <main className="container mx-auto px-6 py-8">
        {!activeScheme ? (
          <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            <div className="text-center space-y-4 py-10">
              <h2 className="text-5xl font-extrabold text-slate-800 tracking-tight">Term Planning Redefined</h2>
              <p className="text-lg text-slate-500 max-w-2xl mx-auto leading-relaxed">
                Step 1: Generate your <span className="text-indigo-600 font-bold">Scheme Book</span>. <br/>
                Step 2: Build individual <span className="text-indigo-600 font-bold">Resource Bundles</span> for each lesson.
              </p>
            </div>

            <InputForm onGenerate={handleGenerate} />

            {error && (
              <div className="bg-red-50 border border-red-200 text-red-700 px-6 py-4 rounded-xl flex items-center gap-3">
                <Layout className="w-5 h-5 text-red-600" />
                {error}
              </div>
            )}
          </div>
        ) : (
          <div className="space-y-6 animate-in fade-in duration-500">
            <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 flex flex-wrap items-center justify-between gap-6 no-print">
              <div className="flex gap-8">
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1">Scheme Detail</label>
                  <p className="text-lg font-bold text-slate-800">{activeScheme.metadata.subject} | {activeScheme.metadata.form}</p>
                </div>
                <div>
                  <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest block mb-1">Status</label>
                  <p className="text-sm font-bold text-emerald-600 flex items-center gap-1">
                    <Sparkles className="w-3 h-3" /> Scheme Ready
                  </p>
                </div>
              </div>
              <div className="flex gap-3">
                <button onClick={() => setActiveScheme(null)} className="bg-white border border-slate-200 text-slate-700 hover:bg-slate-50 px-4 py-2 rounded-lg text-sm font-semibold transition-all flex items-center gap-2">
                  <PlusCircle className="w-4 h-4" /> Reset
                </button>
                <button onClick={() => window.print()} className="bg-slate-100 text-slate-700 hover:bg-slate-200 px-4 py-2 rounded-lg text-sm font-semibold transition-all flex items-center gap-2">
                  <Printer className="w-4 h-4" /> Print
                </button>
              </div>
            </div>

            <div className="bg-indigo-50 border border-indigo-100 p-4 rounded-xl flex items-start gap-4 no-print">
              <div className="bg-indigo-600 p-2 rounded-lg text-white">
                <Info className="w-5 h-5" />
              </div>
              <div>
                <h4 className="font-bold text-indigo-900 text-sm">Step 2: Build Your Bundles</h4>
                <p className="text-indigo-700 text-xs mt-1">
                  Click <span className="font-bold">"Build Bundle"</span> in the table below to generate detailed Lesson Plans, Worksheets, and Slides for any specific lesson.
                </p>
              </div>
            </div>

            <SchemeTable 
              lessons={activeScheme.lessons} 
              metadata={activeScheme.metadata}
              onUpdateLesson={updateLesson} 
              onGenerateResources={handleGenerateResources}
            />
          </div>
        )}
      </main>

      {isLoading && <LoadingOverlay />}
    </div>
  );
};

export default App;

export const getWeekEndingDate = (startDateStr: string, weekIndex: number): string => {
  const date = new Date(startDateStr);
  if (isNaN(date.getTime())) return "TBD";

  // Find the Monday of the week for the provided date
  const day = date.getDay();
  const diff = date.getDate() - day + (day === 0 ? -6 : 1);
  const monday = new Date(date.setDate(diff));

  // Calculate the Friday of the target week (Monday + 4 days + (weekIndex-1) weeks)
  const friday = new Date(monday);
  friday.setDate(monday.getDate() + 4 + (weekIndex - 1) * 7);

  const options: Intl.DateTimeFormatOptions = { 
    weekday: 'short', 
    month: 'short', 
    day: 'numeric', 
    year: 'numeric' 
  };
  return friday.toLocaleDateString('en-US', options);
};

export const getAcademicYears = () => {
  const currentYear = new Date().getFullYear();
  return [
    `${currentYear}/${currentYear + 1}`,
    `${currentYear - 1}/${currentYear}`,
    `${currentYear + 1}/${currentYear + 2}`
  ];
};

import React, { useState, useRef } from 'react';
import { SchemeMetadata } from '../types';
import { getAcademicYears } from '../utils/dateUtils';
import { SUBJECT_TEMPLATES } from '../constants';
import { FileText, Sparkles, Upload, FileUp, X, Loader2, CheckCircle2, Calendar } from 'lucide-react';
import { extractSyllabusInfo } from '../services/geminiService';

interface InputFormProps {
  onGenerate: (metadata: SchemeMetadata, syllabusFile?: { data: string, mimeType: string }) => void;
}

const InputForm: React.FC<InputFormProps> = ({ onGenerate }) => {
  const [formData, setFormData] = useState<SchemeMetadata>({
    subject: '',
    form: '',
    term: '1',
    weeks: 12,
    lessonsPerWeek: 5,
    teacherName: '',
    school: '',
    academicYear: getAcademicYears()[0],
    startDate: new Date().toISOString().split('T')[0]
  });

  const [selectedFile, setSelectedFile] = useState<File | null>(null);
  const [fileBase64, setFileBase64] = useState<string | null>(null);
  const [isExtracting, setIsExtracting] = useState(false);
  const [isExtracted, setIsExtracted] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: name === 'weeks' || name === 'lessonsPerWeek' ? parseInt(value) || 0 : value
    }));
  };

  const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && file.type === 'application/pdf') {
      setSelectedFile(file);
      const reader = new FileReader();
      reader.onload = async (event) => {
        const base64 = (event.target?.result as string).split(',')[1];
        setFileBase64(base64);

        // Auto-extract info
        setIsExtracting(true);
        setIsExtracted(false);
        try {
          const info = await extractSyllabusInfo({ data: base64, mimeType: 'application/pdf' });
          setFormData(prev => ({
            ...prev,
            subject: info.subject || prev.subject,
            form: info.form || prev.form,
            weeks: info.recommendedWeeks || prev.weeks
          }));
          setIsExtracted(true);
        } catch (err) {
          console.error("Auto-extraction failed", err);
        } finally {
          setIsExtracting(false);
        }
      };
      reader.readAsDataURL(file);
    } else if (file) {
      alert("Please upload a PDF file.");
      e.target.value = '';
    }
  };

  const removeFile = () => {
    setSelectedFile(null);
    setFileBase64(null);
    setIsExtracted(false);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleTemplateLoad = (templateId: string) => {
    const template = SUBJECT_TEMPLATES.find(t => t.id === templateId);
    if (template) {
      setFormData(prev => ({
        ...prev,
        subject: template.subject,
        form: template.form
      }));
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.subject) {
      alert("Please specify a subject (or upload a syllabus to auto-detect).");
      return;
    }
    onGenerate(
      formData, 
      fileBase64 ? { data: fileBase64, mimeType: 'application/pdf' } : undefined
    );
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
      <div className="bg-slate-50 border-b border-slate-200 px-6 py-4 flex items-center justify-between">
        <h2 className="text-lg font-semibold flex items-center gap-2 text-slate-800">
          <FileText className="w-5 h-5 text-indigo-600" />
          Setup Scheme Book
        </h2>
        <div className="flex gap-2">
          <select 
            onChange={(e) => handleTemplateLoad(e.target.value)}
            className="text-sm border-slate-300 rounded-lg py-1 px-3 bg-white focus:ring-indigo-500 focus:border-indigo-500"
          >
            <option value="">Quick Templates</option>
            {SUBJECT_TEMPLATES.map(t => (
              <option key={t.id} value={t.id}>{t.name}</option>
            ))}
          </select>
        </div>
      </div>

      <form onSubmit={handleSubmit} className="p-6 space-y-6">
        {/* PDF Syllabus Upload */}
        <div className="space-y-2">
          <label className="text-sm font-medium text-slate-700 flex items-center gap-2">
            <Upload className="w-4 h-4 text-slate-400" />
            Upload Syllabus PDF (AI will auto-detect subject)
          </label>
          <div 
            onClick={() => !selectedFile && !isExtracting && fileInputRef.current?.click()}
            className={`relative border-2 border-dashed rounded-xl p-6 transition-all duration-200 cursor-pointer ${
              selectedFile ? 'border-indigo-200 bg-indigo-50' : 'border-slate-200 hover:border-indigo-400 hover:bg-slate-50'
            } ${isExtracting ? 'opacity-70 cursor-wait' : ''}`}
          >
            <input 
              type="file" 
              ref={fileInputRef} 
              className="hidden" 
              accept="application/pdf"
              onChange={handleFileChange}
              disabled={isExtracting}
            />
            {selectedFile ? (
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className={`p-2 rounded-lg ${isExtracting ? 'bg-indigo-100 animate-pulse' : 'bg-emerald-100'}`}>
                    {isExtracting ? <Loader2 className="w-5 h-5 text-indigo-600 animate-spin" /> : <FileUp className="w-5 h-5 text-emerald-600" />}
                  </div>
                  <div>
                    <div className="flex items-center gap-2">
                       <p className="text-sm font-semibold text-slate-800 truncate max-w-[200px] md:max-w-md">{selectedFile.name}</p>
                       {isExtracted && <CheckCircle2 className="w-4 h-4 text-emerald-500" />}
                    </div>
                    <p className="text-xs text-slate-500">
                      {isExtracting ? 'AI is analyzing syllabus...' : isExtracted ? 'Subject & Grade detected!' : 'Syllabus Attached'}
                    </p>
                  </div>
                </div>
                {!isExtracting && (
                  <button 
                    type="button"
                    onClick={(e) => { e.stopPropagation(); removeFile(); }}
                    className="p-1.5 hover:bg-indigo-200 rounded-full text-indigo-600 transition-colors"
                  >
                    <X className="w-4 h-4" />
                  </button>
                )}
              </div>
            ) : (
              <div className="text-center">
                <div className="mx-auto w-10 h-10 bg-slate-100 rounded-full flex items-center justify-center mb-2">
                  <Upload className="w-5 h-5 text-slate-400" />
                </div>
                <p className="text-sm font-medium text-slate-600">Click to upload your syllabus PDF</p>
                <p className="text-xs text-slate-400 mt-1">AI will automatically identify subject, grade and weeks</p>
              </div>
            )}
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Subject</label>
            <input
              required
              name="subject"
              value={formData.subject}
              onChange={handleChange}
              className={`w-full border-slate-300 rounded-lg px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 border transition-all ${isExtracted ? 'bg-emerald-50 border-emerald-200' : ''}`}
              placeholder="e.g. Mathematics"
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Form / Class</label>
            <input
              required
              name="form"
              value={formData.form}
              onChange={handleChange}
              className={`w-full border-slate-300 rounded-lg px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 border transition-all ${isExtracted ? 'bg-emerald-50 border-emerald-200' : ''}`}
              placeholder="e.g. Form 4"
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Term</label>
            <select
              name="term"
              value={formData.term}
              onChange={handleChange}
              className="w-full border-slate-300 rounded-lg px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 border bg-white"
            >
              <option value="1">1st Term</option>
              <option value="2">2nd Term</option>
              <option value="3">3rd Term</option>
            </select>
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700 flex items-center gap-1.5">
              <Calendar className="w-3.5 h-3.5 text-indigo-500" />
              Term Start Date
            </label>
            <input
              required
              type="date"
              name="startDate"
              value={formData.startDate}
              onChange={handleChange}
              className="w-full border-slate-300 rounded-lg px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 border"
            />
            <p className="text-[10px] text-slate-400">Select any day; weeks will end on Fridays.</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Total Weeks</label>
            <input
              required
              type="number"
              min="1"
              max="20"
              name="weeks"
              value={formData.weeks}
              onChange={handleChange}
              className={`w-full border-slate-300 rounded-lg px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 border ${isExtracted ? 'bg-emerald-50 border-emerald-200' : ''}`}
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Lessons per Week</label>
            <input
              required
              type="number"
              min="1"
              max="10"
              name="lessonsPerWeek"
              value={formData.lessonsPerWeek}
              onChange={handleChange}
              className="w-full border-slate-300 rounded-lg px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 border"
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700 text-indigo-600 font-bold">Total Lessons</label>
            <div className="w-full bg-indigo-50 border border-indigo-100 rounded-lg px-3 py-2 text-indigo-700 font-semibold">
              {formData.weeks * formData.lessonsPerWeek}
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Teacher Name</label>
            <input
              name="teacherName"
              value={formData.teacherName}
              onChange={handleChange}
              className="w-full border-slate-300 rounded-lg px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 border"
              placeholder="e.g. Jane Smith"
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">School Name</label>
            <input
              name="school"
              value={formData.school}
              onChange={handleChange}
              className="w-full border-slate-300 rounded-lg px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 border"
              placeholder="e.g. Riverside Academy"
            />
          </div>
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-700">Academic Year</label>
            <select
              name="academicYear"
              value={formData.academicYear}
              onChange={handleChange}
              className="w-full border-slate-300 rounded-lg px-3 py-2 focus:ring-indigo-500 focus:border-indigo-500 border bg-white"
            >
              {getAcademicYears().map(year => (
                <option key={year} value={year}>{year}</option>
              ))}
            </select>
          </div>
        </div>

        <div className="pt-4 border-t border-slate-100">
          <button
            type="submit"
            disabled={isExtracting}
            className="w-full md:w-auto bg-indigo-600 hover:bg-indigo-700 text-white font-semibold py-3 px-8 rounded-lg shadow-md transition-all duration-200 flex items-center justify-center gap-2 group disabled:opacity-50"
          >
            {isExtracting ? <Loader2 className="w-5 h-5 animate-spin" /> : <Sparkles className="w-5 h-5 group-hover:rotate-12 transition-transform" />}
            {isExtracting ? 'Analyzing Syllabus...' : 'Generate Complete Scheme Book'}
          </button>
        </div>
      </form>
    </div>
  );
};

export default InputForm;

import React, { useRef, useState } from 'react';
import { Lesson, SchemeMetadata } from '../types';
import { Bold, Italic, PackageOpen, FileText, Presentation, FileDown, Loader2, Sparkles, BookOpen, ClipboardCheck } from 'lucide-react';
import { downloadLessonResourcesZip } from '../utils/exportUtils';

interface SchemeTableProps {
  lessons: Lesson[];
  metadata: SchemeMetadata;
  onUpdateLesson: (id: string, field: keyof Lesson, value: any) => void;
  onGenerateResources: (lesson: Lesson) => Promise<void>;
}

const RichEvaluationCell: React.FC<{
  value: string;
  onChange: (val: string) => void;
}> = ({ value, onChange }) => {
  const editorRef = useRef<HTMLDivElement>(null);
  const [isFocused, setIsFocused] = useState(false);

  const handleCommand = (command: string) => {
    document.execCommand(command, false);
    if (editorRef.current) {
      onChange(editorRef.current.innerHTML);
    }
  };

  return (
    <div className="relative group flex flex-col min-h-[120px]">
      {isFocused && (
        <div className="absolute -top-10 left-0 flex items-center gap-1 bg-white border border-slate-200 shadow-sm rounded-md p-1 z-10 no-print">
          <button
            onMouseDown={(e) => { e.preventDefault(); handleCommand('bold'); }}
            className="p-1 hover:bg-slate-100 rounded text-slate-600"
          >
            <Bold className="w-3.5 h-3.5" />
          </button>
          <button
            onMouseDown={(e) => { e.preventDefault(); handleCommand('italic'); }}
            className="p-1 hover:bg-slate-100 rounded text-slate-600"
          >
            <Italic className="w-3.5 h-3.5" />
          </button>
        </div>
      )}
      <div
        ref={editorRef}
        contentEditable
        onFocus={() => setIsFocused(true)}
        onBlur={() => {
          setIsFocused(false);
          if (editorRef.current) {
            onChange(editorRef.current.innerHTML);
          }
        }}
        className="w-full h-full min-h-[120px] bg-transparent border-none focus:ring-1 focus:ring-indigo-500 rounded p-2 text-xs outline-none overflow-y-auto"
        dangerouslySetInnerHTML={{ __html: value }}
      />
    </div>
  );
};

const SchemeTable: React.FC<SchemeTableProps> = ({ lessons, metadata, onUpdateLesson, onGenerateResources }) => {
  // Extract unique resources and assessments for the summary sections
  const uniqueResources = Array.from(new Set(lessons.map(l => l.resources).filter(Boolean)));
  const uniqueAssessments = Array.from(new Set(lessons.map(l => l.assessment).filter(Boolean)));

  return (
    <div className="space-y-8">
      {/* Table Header Section (Print only) */}
      <div className="hidden print:block mb-6 border-b-2 border-slate-800 pb-4">
        <h1 className="text-2xl font-bold uppercase text-center mb-4">Scheme of Work - Term {metadata.term}</h1>
        <div className="grid grid-cols-3 gap-4 text-sm">
          <div><span className="font-bold">Subject:</span> {metadata.subject}</div>
          <div><span className="font-bold">Class/Grade:</span> {metadata.form}</div>
          <div><span className="font-bold">Teacher:</span> {metadata.teacherName}</div>
          <div><span className="font-bold">School:</span> {metadata.school}</div>
          <div><span className="font-bold">Academic Year:</span> {metadata.academicYear}</div>
          <div><span className="font-bold">Total Weeks:</span> {metadata.weeks}</div>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse table-fixed">
            <thead className="bg-slate-800 text-white text-[10px] uppercase tracking-wider font-semibold">
              <tr>
                <th className="px-3 py-3 border-r border-slate-700 w-12 text-center">Wk</th>
                <th className="px-3 py-3 border-r border-slate-700 w-32">Week Ending</th>
                <th className="px-3 py-3 border-r border-slate-700 w-12 text-center">L#</th>
                <th className="px-3 py-3 border-r border-slate-700 w-44">Topic</th>
                <th className="px-3 py-3 border-r border-slate-700 w-56">Objectives</th>
                <th className="px-3 py-3 border-r border-slate-700 w-44">Concepts</th>
                <th className="px-3 py-3 border-r border-slate-700 w-56">Activities</th>
                <th className="px-3 py-3 border-r border-slate-700 w-44">References</th>
                <th className="px-3 py-3 border-r border-slate-700 w-40">Assess</th>
                <th className="px-3 py-3 border-r border-slate-700 w-40">HW</th>
                <th className="px-3 py-3 border-r border-slate-700 w-56">Evaluation</th>
                <th className="px-3 py-3 w-36 no-print text-center">Lesson Bundle</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200">
              {lessons.map((lesson) => (
                <tr key={lesson.id} className="hover:bg-slate-50 transition-colors text-xs">
                  <td className="px-3 py-2 border-r border-slate-200 text-center font-bold text-slate-500">{lesson.week}</td>
                  <td className="px-3 py-2 border-r border-slate-200">
                    <input
                      className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-500 rounded p-1"
                      value={lesson.weekEnding}
                      onChange={(e) => onUpdateLesson(lesson.id, 'weekEnding', e.target.value)}
                    />
                  </td>
                  <td className="px-3 py-2 border-r border-slate-200 text-center text-slate-500 font-medium">{lesson.lessonNumber}</td>
                  <td className="px-3 py-2 border-r border-slate-200 align-top">
                    <textarea
                      rows={2}
                      className="w-full bg-transparent border-none focus:ring-1 focus:ring-indigo-500 rounded p-1 resize-none font-semibold text-slate-800"
                      value={lesson.topic}
                      onChange={(e) => onUpdateLesson(lesson.id, 'topic', e.target.value)}
                    />
                  </td>
                  <td className="px-3 py-2 border-r border-slate-200 align-top text-slate-600">
                    {lesson.objectives}
                  </td>
                  <td className="px-3 py-2 border-r border-slate-200 align-top text-slate-600 italic">
                    {lesson.concepts}
                  </td>
                  <td className="px-3 py-2 border-r border-slate-200 align-top text-slate-600">
                    {lesson.activities}
                  </td>
                  <td className="px-3 py-2 border-r border-slate-200 align-top text-slate-500">
                    {lesson.resources}
                  </td>
                  <td className="px-3 py-2 border-r border-slate-200 align-top text-slate-500">
                    {lesson.assessment}
                  </td>
                  <td className="px-3 py-2 border-r border-slate-200 align-top text-slate-500">
                    {lesson.homework}
                  </td>
                  <td className="px-3 py-2 border-r border-slate-200 align-top">
                    <RichEvaluationCell
                      value={lesson.evaluation}
                      onChange={(val) => onUpdateLesson(lesson.id, 'evaluation', val)}
