                            <FileText className="w-3 h-3 text-blue-500" />
                            <FileDown className="w-3 h-3 text-indigo-500" />
                            <Presentation className="w-3 h-3 text-orange-500" />
                          </div>
                          <button
                            onClick={() => downloadLessonResourcesZip(lesson, metadata)}
                            className="w-full flex items-center justify-center gap-1.5 bg-indigo-600 hover:bg-indigo-700 text-white px-2 py-1.5 rounded text-[10px] font-bold shadow-sm transition-all"
                          >
                            <PackageOpen className="w-3 h-3" />
                            Download ZIP
                          </button>
                        </>
                      ) : (
                        <button
                          onClick={() => onGenerateResources(lesson)}
                          disabled={lesson.isGeneratingResources}
                          className="w-full flex items-center justify-center gap-1.5 bg-white border border-indigo-200 text-indigo-600 hover:bg-indigo-50 px-2 py-2 rounded text-[10px] font-bold shadow-sm transition-all disabled:opacity-50"
                        >
                          {lesson.isGeneratingResources ? (
                            <Loader2 className="w-3 h-3 animate-spin" />
                          ) : (
                            <Sparkles className="w-3 h-3" />
                          )}
                          {lesson.isGeneratingResources ? 'Generating...' : 'Build Bundle'}
                        </button>
                      )}
                    </div>
