                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {/* Footer Summary Sections */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 break-inside-avoid">
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
          <div className="flex items-center gap-2 mb-4">
            <ClipboardCheck className="w-5 h-5 text-indigo-600" />
            <h3 className="font-bold text-slate-800">Assessment Summary</h3>
          </div>
          <div className="space-y-2">
            {uniqueAssessments.length > 0 ? (
              <ul className="list-disc list-inside text-sm text-slate-600 space-y-1">
                {uniqueAssessments.slice(0, 10).map((item, idx) => (
                  <li key={idx}>{item}</li>
                ))}
              </ul>
            ) : (
              <p className="text-sm text-slate-400 italic">No specific assessments listed yet.</p>
            )}
          </div>
        </div>

        <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6">
          <div className="flex items-center gap-2 mb-4">
            <BookOpen className="w-5 h-5 text-indigo-600" />
            <h3 className="font-bold text-slate-800">Resources List</h3>
          </div>
          <div className="space-y-2">
            {uniqueResources.length > 0 ? (
              <ul className="list-disc list-inside text-sm text-slate-600 space-y-1">
                {uniqueResources.slice(0, 10).map((item, idx) => (
                  <li key={idx}>{item}</li>
                ))}
              </ul>
            ) : (
              <p className="text-sm text-slate-400 italic">No resources listed yet.</p>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default SchemeTable;
